// === GOOGLE FONTS INLINE + LOAD HELPERS (for export) (BEGIN) =======================
async function blobToDataURL(b: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(String(r.result || ''));
    r.onerror = reject;
    r.readAsDataURL(b);
  });
}

const MOBILE_MAX_IMAGE = 2400;
const DESKTOP_MAX_IMAGE = 2200;

type DownscaleOutputType = "image/png" | "image/jpeg" | "image/webp";

function getRuntimeMaxImageDimension() {
  if (typeof window === "undefined") return DESKTOP_MAX_IMAGE;
  const ua = typeof navigator === "undefined" ? "" : navigator.userAgent;
  const isMobileRuntime =
    window.innerWidth < 768 || /iPhone|iPad|Android/i.test(ua);
  return isMobileRuntime ? MOBILE_MAX_IMAGE : DESKTOP_MAX_IMAGE;
}

/** Ensure the given families are actually loaded before we rasterize. */
function waitForExportTimeout(ms: number): Promise<void> {
  if (ms <= 0) return Promise.resolve();
  return new Promise((resolve) => {
    if (typeof window !== "undefined") {
      window.setTimeout(resolve, ms);
      return;
    }
    setTimeout(resolve, ms);
  });
}

async function waitForExportPromise<T>(
  promise: Promise<T> | undefined | null,
  timeoutMs: number
): Promise<T | undefined> {
  if (!promise || typeof (promise as any).then !== "function") return undefined;
  return Promise.race([
    promise.catch(() => undefined),
    waitForExportTimeout(timeoutMs).then(() => undefined),
  ]);
}

async function fetchExportResource(
  input: RequestInfo | URL,
  init?: RequestInit,
  timeoutMs = 3500
) {
  const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
  const timeout = controller && typeof window !== "undefined"
    ? window.setTimeout(() => controller.abort(), timeoutMs)
    : null;
  try {
    return await fetch(input, {
      ...init,
      signal: controller?.signal ?? init?.signal,
    });
  } finally {
    if (timeout !== null) window.clearTimeout(timeout);
  }
}

async function blobToDataURLForExport(blob: Blob, timeoutMs = 2500) {
  const dataUrl = await waitForExportPromise(blobToDataURL(blob), timeoutMs);
  if (!dataUrl) throw new Error("blob data url timed out");
  return dataUrl;
}

async function waitForFamilies(
  families: (string | undefined)[],
  timeoutMs = 7000
): Promise<void> {
  const used = Array.from(new Set(families.filter(Boolean) as string[]));
  const deadline = Date.now() + timeoutMs;

  // First, wait for any pending font loads globally.
  await waitForExportPromise((document as any).fonts?.ready, Math.min(timeoutMs, 1500));

  // Then explicitly request each family at a few representative sizes/weights.
  for (const fam of used) {
    const faces = [
      `400 16px "${fam}"`,
      `700 32px "${fam}"`,
      `900 48px "${fam}"`,
    ];
    for (const desc of faces) {
      try {
        const p = (document as any).fonts?.load
          ? (document as any).fonts.load(desc)
          : Promise.resolve();
        // Simple timeout guard so we don't hang forever
        const remaining = Math.max(0, deadline - Date.now());
        await waitForExportPromise(p, Math.min(remaining, 1500));
      } catch {}
    }
  }
}

/** Export pre-flight: force browser to realize/load requested font families. */
async function forceFontRender(families: (string | undefined)[]): Promise<void> {
  const uniq = Array.from(new Set(families.filter(Boolean) as string[]));
  await waitForExportPromise((document as any).fonts?.ready, 1500);
  await Promise.all(
    uniq.map(async (f) => {
      try {
        await waitForExportPromise((document as any).fonts?.load?.(`16px "${f}"`), 1200);
      } catch {}
    })
  );
}

function normalizeFontFamilyName(raw: string): string {
  return String(raw || "").trim().replace(/^['"]|['"]$/g, "").toLowerCase();
}

function guessFontFormat(url: string): string {
  const clean = url.split("?")[0].toLowerCase();
  if (clean.endsWith(".woff2")) return "woff2";
  if (clean.endsWith(".woff")) return "woff";
  if (clean.endsWith(".otf")) return "opentype";
  return "truetype";
}

function hslToRgb(h: number, s: number, l: number): [number, number, number] {
  const hue = ((h % 360) + 360) % 360;
  const sat = Math.max(0, Math.min(1, s));
  const light = Math.max(0, Math.min(1, l));
  const c = (1 - Math.abs(2 * light - 1)) * sat;
  const x = c * (1 - Math.abs(((hue / 60) % 2) - 1));
  const m = light - c / 2;

  let r = 0;
  let g = 0;
  let b = 0;

  if (hue < 60) [r, g, b] = [c, x, 0];
  else if (hue < 120) [r, g, b] = [x, c, 0];
  else if (hue < 180) [r, g, b] = [0, c, x];
  else if (hue < 240) [r, g, b] = [0, x, c];
  else if (hue < 300) [r, g, b] = [x, 0, c];
  else [r, g, b] = [c, 0, x];

  return [
    Math.round((r + m) * 255),
    Math.round((g + m) * 255),
    Math.round((b + m) * 255),
  ];
}

type TemplateBackgroundPaletteSample = {
  rgb: LightingRgb;
  hex: string;
  count: number;
  h: number;
  s: number;
  l: number;
  lum: number;
};

const templateBackgroundPaletteCache = new Map<string, Palette>();

function rgbToHslForTemplatePalette(color: LightingRgb) {
  const rn = color.r / 255;
  const gn = color.g / 255;
  const bn = color.b / 255;
  const max = Math.max(rn, gn, bn);
  const min = Math.min(rn, gn, bn);
  const d = max - min;
  const l = (max + min) / 2;
  let h = 0;
  let s = 0;

  if (d) {
    s = d / (1 - Math.abs(2 * l - 1));
    if (max === rn) h = ((gn - bn) / d) % 6;
    else if (max === gn) h = (bn - rn) / d + 2;
    else h = (rn - gn) / d + 4;
    h *= 60;
    if (h < 0) h += 360;
  }

  return {
    h,
    s: Math.max(0, Math.min(1, s)),
    l: Math.max(0, Math.min(1, l)),
  };
}

function normalizePaletteHexString(hex: string, fallback = "#FFFFFF") {
  const value = String(hex || "").trim();
  if (!/^#[0-9a-f]{6}$/i.test(value)) return fallback;
  return value.toUpperCase();
}

function paletteHexFromRgb(color: LightingRgb) {
  return rgbToHex(color).toUpperCase();
}

function paletteHexFromHsl(h: number, s: number, l: number) {
  const [r, g, b] = hslToRgb(h, s, l);
  return paletteHexFromRgb({ r, g, b });
}

function hueDistance(a: number, b: number) {
  const diff = Math.abs((((a - b) % 360) + 540) % 360 - 180);
  return Math.min(180, diff);
}

function rgbDistance(a: LightingRgb, b: LightingRgb) {
  const dr = a.r - b.r;
  const dg = a.g - b.g;
  const db = a.b - b.b;
  return Math.sqrt(dr * dr + dg * dg + db * db);
}

function pickTemplatePaletteSample(
  samples: TemplateBackgroundPaletteSample[],
  predicate: (sample: TemplateBackgroundPaletteSample) => boolean,
  score: (sample: TemplateBackgroundPaletteSample) => number
) {
  let winner: TemplateBackgroundPaletteSample | null = null;
  let bestScore = -Infinity;
  for (const sample of samples) {
    if (!predicate(sample)) continue;
    const nextScore = score(sample);
    if (nextScore > bestScore) {
      bestScore = nextScore;
      winner = sample;
    }
  }
  return winner;
}

function resolveTemplateBackgroundPaletteSource(tpl: TemplateSpec, fmt: Format) {
  const variant: any = tpl.formats?.[fmt] ?? tpl.formats?.square ?? tpl.base ?? {};
  const candidates = [
    variant.backgroundUrl,
    variant.bgUploadUrl,
    variant.bgUrl,
    tpl.preview,
  ];
  return String(candidates.find((candidate) => typeof candidate === "string" && candidate.trim()) || "").trim();
}

async function analyzeTemplateBackgroundPalette(src: string): Promise<Palette | null> {
  const raw = String(src || "").trim();
  if (!raw || typeof window === "undefined" || typeof document === "undefined") return null;

  let cacheKey = raw;
  try {
    cacheKey = new URL(raw, window.location.href).toString();
  } catch {}

  const cached = templateBackgroundPaletteCache.get(cacheKey);
  if (cached) return { ...cached };

  try {
    const img = await new Promise<HTMLImageElement>((resolve, reject) => {
      const node = new Image();
      node.crossOrigin = "anonymous";
      node.decoding = "async";
      node.onload = () => resolve(node);
      node.onerror = () => reject(new Error("Failed to load template background for palette analysis."));
      node.src = cacheKey;
    });

    const naturalWidth = img.naturalWidth || img.width || 1;
    const naturalHeight = img.naturalHeight || img.height || 1;
    const maxSide = 180;
    const scale = Math.min(1, maxSide / Math.max(naturalWidth, naturalHeight));
    const width = Math.max(1, Math.round(naturalWidth * scale));
    const height = Math.max(1, Math.round(naturalHeight * scale));
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d", { willReadFrequently: true });
    if (!ctx) return null;

    ctx.drawImage(img, 0, 0, width, height);
    const data = ctx.getImageData(0, 0, width, height).data;
    const buckets = new Map<string, { r: number; g: number; b: number; count: number }>();

    for (let i = 0; i < data.length; i += 4) {
      const alpha = data[i + 3];
      if (alpha < 180) continue;

      const r = data[i];
      const g = data[i + 1];
      const b = data[i + 2];
      const key = `${Math.round(r / 24) * 24},${Math.round(g / 24) * 24},${Math.round(b / 24) * 24}`;
      const bucket = buckets.get(key);
      if (bucket) {
        bucket.r += r;
        bucket.g += g;
        bucket.b += b;
        bucket.count += 1;
      } else {
        buckets.set(key, { r, g, b, count: 1 });
      }
    }

    const samples = Array.from(buckets.values())
      .map((bucket) => {
        const rgb = {
          r: Math.round(bucket.r / bucket.count),
          g: Math.round(bucket.g / bucket.count),
          b: Math.round(bucket.b / bucket.count),
        };
        const hsl = rgbToHslForTemplatePalette(rgb);
        return {
          rgb,
          hex: paletteHexFromRgb(rgb),
          count: bucket.count,
          h: hsl.h,
          s: hsl.s,
          l: hsl.l,
          lum: luminanceOfRgb(rgb),
        };
      })
      .sort((a, b) => b.count - a.count);

    if (!samples.length) return null;

    const directedPalette = createDirectedPalette(
      samples.map((sample) => ({
        hex: sample.hex,
        h: sample.h,
        s: sample.s,
        l: sample.l,
        weight: sample.count,
      }))
    );
    const baseHex = directedPalette.atmosphericColor?.hex || directedPalette.dominant.hex;
    const luxuryHex = directedPalette.luxuryColor?.hex || directedPalette.support.hex;
    const energyHex = directedPalette.energyColor?.hex || directedPalette.accent.hex;
    const neutralHex = directedPalette.readabilityColor?.hex || directedPalette.support.hex;
    const shadowHex = directedPalette.shadowColor?.hex || darkenHex(baseHex, 45);

    const palette: Palette = {
      bgFrom: baseHex,
      bgTo: shadowHex,
      secondary: baseHex,
      primary: luxuryHex,
      neutral: neutralHex,
      accent: energyHex,
    };
    templateBackgroundPaletteCache.set(cacheKey, { ...palette });
    return palette;
  } catch {
    return null;
  }
}

const tintedTextureCache = new Map<string, string>();
const canvasTintCache = new Map<string, string>();

type CanvasPreloadJob = {
  key: string;
  src: string;
  label: string;
  kind?: "image" | "tintedTexture";
  hue?: number;
};

type CanvasPreloadQueueStep = {
  job: CanvasPreloadJob;
  index: number;
  total: number;
  done: number;
  errors: number;
  phase: "start" | "done";
};

const CANVAS_PRELOAD_PROBLEM_COPY = [
  "Solving: make the event clear in the first three seconds.",
  "Solving: keep post and story versions matched without rebuilding twice.",
  "Solving: protect mobile memory by loading one premium layer at a time.",
  "Solving: keep the date, venue, price, and social details export-ready.",
  "Solving: prepare the design so edits stay responsive after load.",
];

function stablePreloadHash(value: string) {
  if (value.length > 2048) {
    value = `${value.slice(0, 768)}:${value.length}:${value.slice(-768)}`;
  }
  let hash = 2166136261;
  for (let i = 0; i < value.length; i += 1) {
    hash ^= value.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function canPreloadCanvasSource(src?: string | null) {
  const value = String(src || "").trim();
  return !!value && !value.startsWith("about:") && !value.startsWith("javascript:");
}

function buildCanvasPreloadKey(src: string, kind: CanvasPreloadJob["kind"] = "image", hue = 0) {
  return `${kind}:${stablePreloadHash(src)}:${Math.round(Number(hue) || 0)}`;
}

function waitForCanvasPreloadFrame() {
  if (typeof window === "undefined") return Promise.resolve();
  return new Promise<void>((resolve) => {
    let done = false;
    const finish = () => {
      if (done) return;
      done = true;
      window.clearTimeout(timeout);
      resolve();
    };
    const timeout = window.setTimeout(finish, 80);
    window.requestAnimationFrame(() => {
      finish();
    });
  });
}

function waitForCanvasPreloadPause(ms: number) {
  if (!ms || typeof window === "undefined") return Promise.resolve();
  return new Promise<void>((resolve) => {
    window.setTimeout(resolve, ms);
  });
}

async function loadCanvasPreloadImage(src: string): Promise<HTMLImageElement> {
  if (!canPreloadCanvasSource(src)) throw new Error("Missing image source");
  const img = new Image();
  if (!src.startsWith("data:") && !src.startsWith("blob:")) {
    img.crossOrigin = "anonymous";
  }
  img.decoding = "async";
  img.loading = "eager";
  await new Promise<void>((resolve, reject) => {
    const timeout = typeof window !== "undefined"
      ? window.setTimeout(() => {
          cleanup();
          reject(new Error("Image preload timed out"));
        }, 7000)
      : null;
    const cleanup = () => {
      if (timeout !== null) window.clearTimeout(timeout);
      img.onload = null;
      img.onerror = null;
    };
    img.onload = () => {
      cleanup();
      resolve();
    };
    img.onerror = () => {
      cleanup();
      reject(new Error("Image failed to preload"));
    };
    img.src = src;
    if (img.complete && img.naturalWidth > 0 && img.naturalHeight > 0) {
      cleanup();
      resolve();
    }
  });
  if ((img as any).decode) {
    try {
      await waitForExportPromise((img as any).decode(), 1500);
    } catch {
      // The onload path already proved the browser has the image.
    }
  }
  return img;
}

async function waitForHtmlImageElement(img: HTMLImageElement) {
  if (!img) throw new Error("Missing image element");
  if (img.complete && (!img.naturalWidth || !img.naturalHeight)) {
    throw new Error("Image failed to load");
  }
  if (!(img.complete && img.naturalWidth > 0 && img.naturalHeight > 0)) {
    await new Promise<void>((resolve, reject) => {
      const timeout = window.setTimeout(() => {
        cleanup();
        reject(new Error("Image load timed out"));
      }, 8000);
      const cleanup = () => {
        window.clearTimeout(timeout);
        img.removeEventListener("load", onLoad);
        img.removeEventListener("error", onError);
      };
      const onLoad = () => {
        cleanup();
        resolve();
      };
      const onError = () => {
        cleanup();
        reject(new Error("Image failed to load"));
      };
      img.addEventListener("load", onLoad, { once: true });
      img.addEventListener("error", onError, { once: true });
    });
  }
  if ((img as any).decode) {
    try {
      await waitForExportPromise((img as any).decode(), 1500);
    } catch {
      // A loaded image can still throw on decode in Safari. Keep the loaded image.
    }
  }
  if (!(img.complete && img.naturalWidth > 0 && img.naturalHeight > 0)) {
    throw new Error("Image did not decode");
  }
}

async function preloadCanvasImageUrl(src?: string | null) {
  if (!canPreloadCanvasSource(src)) return true;
  try {
    await loadCanvasPreloadImage(String(src));
    return true;
  } catch {
    return false;
  }
}

async function bakeTintedTextureSource(src: string, hue: number) {
  if (!src || !hue) {
    await preloadCanvasImageUrl(src);
    return src;
  }

  const cacheKey = `${src}|${Math.round(hue)}`;
  const cached = tintedTextureCache.get(cacheKey);
  if (cached) return cached;

  const img = await loadCanvasPreloadImage(src);
  try {
    const canvas = document.createElement("canvas");
    canvas.width = img.naturalWidth || img.width;
    canvas.height = img.naturalHeight || img.height;
    const ctx = canvas.getContext("2d", { willReadFrequently: true });
    if (!ctx || !canvas.width || !canvas.height) return src;

    ctx.drawImage(img, 0, 0);
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const [tr, tg, tb] = hslToRgb(hue, 1, 0.5);

    for (let i = 0; i < data.length; i += 4) {
      const alpha = data[i + 3];
      if (alpha === 0) continue;

      const luminance =
        (0.2126 * data[i] + 0.7152 * data[i + 1] + 0.0722 * data[i + 2]) / 255;
      const boosted = Math.max(0, Math.min(1, luminance * 1.15 + 0.05));

      data[i] = Math.round(tr * boosted);
      data[i + 1] = Math.round(tg * boosted);
      data[i + 2] = Math.round(tb * boosted);
    }

    ctx.putImageData(imageData, 0, 0);
    const tinted = canvas.toDataURL("image/png");
    tintedTextureCache.set(cacheKey, tinted);
    return tinted;
  } catch {
    return src;
  }
}

function applyCssHueRotatePixel(
  r: number,
  g: number,
  b: number,
  degrees: number
) {
  const rad = (degrees * Math.PI) / 180;
  const cos = Math.cos(rad);
  const sin = Math.sin(rad);
  const nr =
    (0.213 + cos * 0.787 - sin * 0.213) * r +
    (0.715 - cos * 0.715 - sin * 0.715) * g +
    (0.072 - cos * 0.072 + sin * 0.928) * b;
  const ng =
    (0.213 - cos * 0.213 + sin * 0.143) * r +
    (0.715 + cos * 0.285 + sin * 0.14) * g +
    (0.072 - cos * 0.072 - sin * 0.283) * b;
  const nb =
    (0.213 - cos * 0.213 - sin * 0.787) * r +
    (0.715 - cos * 0.715 + sin * 0.715) * g +
    (0.072 + cos * 0.928 + sin * 0.072) * b;

  return [
    Math.max(0, Math.min(255, Math.round(nr))),
    Math.max(0, Math.min(255, Math.round(ng))),
    Math.max(0, Math.min(255, Math.round(nb))),
  ] as const;
}

async function bakeCanvasTintSource(
  src: string,
  hue: number,
  mode: "hue" | "colorize" = "hue"
) {
  if (!src || !hue) {
    await preloadCanvasImageUrl(src);
    return src;
  }

  const cacheKey = `${src}|${mode}|${Math.round(hue)}`;
  const cached = canvasTintCache.get(cacheKey);
  if (cached) return cached;

  const img = await loadCanvasPreloadImage(src);
  try {
    const canvas = document.createElement("canvas");
    canvas.width = img.naturalWidth || img.width;
    canvas.height = img.naturalHeight || img.height;
    const ctx = canvas.getContext("2d", { willReadFrequently: true });
    if (!ctx || !canvas.width || !canvas.height) return src;

    ctx.drawImage(img, 0, 0);
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const target = mode === "colorize" ? hslToRgb(hue, 1, 0.5) : null;

    for (let i = 0; i < data.length; i += 4) {
      if (data[i + 3] === 0) continue;

      if (target) {
        const luminance =
          (0.2126 * data[i] + 0.7152 * data[i + 1] + 0.0722 * data[i + 2]) / 255;
        const boosted = Math.max(0, Math.min(1, luminance * 1.15 + 0.05));
        data[i] = Math.round(target[0] * boosted);
        data[i + 1] = Math.round(target[1] * boosted);
        data[i + 2] = Math.round(target[2] * boosted);
      } else {
        const [r, g, b] = applyCssHueRotatePixel(data[i], data[i + 1], data[i + 2], hue);
        data[i] = r;
        data[i + 1] = g;
        data[i + 2] = b;
      }
    }

    ctx.putImageData(imageData, 0, 0);
    const tinted = canvas.toDataURL("image/png");
    canvasTintCache.set(cacheKey, tinted);
    return tinted;
  } catch {
    return src;
  }
}

function applyExportCssColorFilterToCanvas(
  ctx: CanvasRenderingContext2D,
  width: number,
  height: number,
  filterCss?: string
) {
  try {
    const ops: { name: string; value: number }[] = [];
    const re = /([a-z-]+)\(([^()]*)\)/gi;
    let match: RegExpExecArray | null;
    while ((match = re.exec(String(filterCss || "")))) {
      const name = match[1].toLowerCase();
      const rawValue = String(match[2] || "").trim();
      const numeric = rawValue.match(/^([-+]?\d*\.?\d+)(%|deg|rad|turn)?$/i);
      if (!numeric) continue;

      const number = Number(numeric[1]);
      const unit = String(numeric[2] || "").toLowerCase();
      if (!Number.isFinite(number)) continue;

      let value = number;
      if (name === "hue-rotate") {
        if (unit === "rad") value = number * (180 / Math.PI);
        else if (unit === "turn") value = number * 360;
      } else if (unit === "%") {
        value = number / 100;
      }

      if (
        name === "brightness" ||
        name === "contrast" ||
        name === "saturate" ||
        name === "hue-rotate"
      ) {
        ops.push({ name, value });
      }
    }
    if (!ops.length) return false;

    const imageData = ctx.getImageData(0, 0, width, height);
    const data = imageData.data;
    const clampChannel = (value: number) =>
      Math.max(0, Math.min(255, Math.round(value * 255)));

    for (let i = 0; i < data.length; i += 4) {
      let r = data[i] / 255;
      let g = data[i + 1] / 255;
      let b = data[i + 2] / 255;

      for (const op of ops) {
        if (op.name === "brightness") {
          r *= Math.max(0, op.value);
          g *= Math.max(0, op.value);
          b *= Math.max(0, op.value);
        } else if (op.name === "contrast") {
          const amount = Math.max(0, op.value);
          r = (r - 0.5) * amount + 0.5;
          g = (g - 0.5) * amount + 0.5;
          b = (b - 0.5) * amount + 0.5;
        } else if (op.name === "saturate") {
          const amount = Math.max(0, op.value);
          const lr = 0.213 * r + 0.715 * g + 0.072 * b;
          r = lr + (r - lr) * amount;
          g = lr + (g - lr) * amount;
          b = lr + (b - lr) * amount;
        } else if (op.name === "hue-rotate") {
          const rotated = applyCssHueRotatePixel(r * 255, g * 255, b * 255, op.value);
          r = rotated[0] / 255;
          g = rotated[1] / 255;
          b = rotated[2] / 255;
        }
      }

      data[i] = clampChannel(r);
      data[i + 1] = clampChannel(g);
      data[i + 2] = clampChannel(b);
    }

    ctx.putImageData(imageData, 0, 0);
    return true;
  } catch {
    return false;
  }
}

async function preloadCanvasJobsSequentially(
  jobs: CanvasPreloadJob[],
  opts: {
    onStep?: (step: CanvasPreloadQueueStep) => void;
    pauseMs?: number;
    shouldCancel?: () => boolean;
  } = {}
) {
  let errors = 0;
  const total = jobs.length;

  for (let index = 0; index < jobs.length; index += 1) {
    if (opts.shouldCancel?.()) break;
    const job = jobs[index];
    opts.onStep?.({ job, index, total, done: index, errors, phase: "start" });

    const ok =
      job.kind === "tintedTexture"
        ? await bakeTintedTextureSource(job.src, Number(job.hue || 0)).then(() => true).catch(() => false)
        : await preloadCanvasImageUrl(job.src);
    if (!ok) errors += 1;

    opts.onStep?.({ job, index, total, done: index + 1, errors, phase: "done" });
    await waitForCanvasPreloadFrame();
    await waitForCanvasPreloadPause(opts.pauseMs ?? 0);
  }

  return { errors };
}

function TintedTextureImage({
  src,
  hue,
  tintMode = "colorize",
  fallbackFilter,
  style,
  ...imgProps
}: {
  src: string;
  hue: number;
  tintMode?: "hue" | "colorize";
  fallbackFilter?: string;
  style: React.CSSProperties;
} & React.ImgHTMLAttributes<HTMLImageElement>) {
  const [displaySrc, setDisplaySrc] = React.useState(src);
  const [displayFilter, setDisplayFilter] = React.useState<string | undefined>(undefined);

  React.useEffect(() => {
    let cancelled = false;

    if (!src || !hue) {
      setDisplaySrc(src);
      setDisplayFilter(undefined);
      return () => {
        cancelled = true;
      };
    }

    setDisplaySrc(src);
    setDisplayFilter(fallbackFilter);

    const bakePromise =
      tintMode === "colorize"
        ? bakeTintedTextureSource(src, hue)
        : bakeCanvasTintSource(src, hue, "hue");

    void bakePromise
      .then((nextSrc) => {
        if (!cancelled) {
          setDisplaySrc(nextSrc || src);
          setDisplayFilter(nextSrc && nextSrc !== src ? undefined : fallbackFilter);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setDisplaySrc(src);
          setDisplayFilter(fallbackFilter);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [fallbackFilter, src, hue, tintMode]);

  const mergedStyle =
    displayFilter && displayFilter !== "none"
      ? { ...style, filter: displayFilter, WebkitFilter: displayFilter }
      : style;

  return (
    <img
      {...imgProps}
      src={displaySrc}
      alt={imgProps.alt ?? ""}
      draggable={false}
      style={mergedStyle}
    />
  );
}

async function inlineCssUrlsToData(css: string): Promise<string> {
  if (!css) return css;
  const urlMatches = Array.from(css.matchAll(/url\((['"]?)(.*?)\1\)/g));
  if (!urlMatches.length) return css;

  let nextCss = css;
  const cache = new Map<string, string>();

  for (const match of urlMatches) {
    const rawUrl = String(match[2] || "").trim();
    if (!rawUrl || rawUrl.startsWith("data:")) continue;

    const absUrl = rawUrl.startsWith("http")
      ? rawUrl
      : new URL(rawUrl, window.location.href).toString();
    if (!cache.has(absUrl)) {
      try {
        const res = await fetch(absUrl, { mode: "cors", credentials: "omit", cache: "no-store" });
        if (!res.ok) throw new Error(`font fetch failed: ${res.status}`);
        const dataUrl = await blobToDataURL(await res.blob());
        cache.set(absUrl, dataUrl);
      } catch {
        cache.set(absUrl, rawUrl);
      }
    }
    const embedded = cache.get(absUrl) || rawUrl;
    nextCss = nextCss.split(rawUrl).join(embedded);
  }

  return nextCss;
}

async function buildLocalFontEmbedCss(families: string[]): Promise<string> {
  const uniq = Array.from(new Set(families.filter(Boolean)));
  if (!uniq.length) return "";

  const rules: string[] = [];
  const byNormalized = new Map<string, string>(
    Object.keys(FONT_FILE_MAP).map((k) => [normalizeFontFamilyName(k), FONT_FILE_MAP[k]])
  );

  for (const family of uniq) {
    const normalized = normalizeFontFamilyName(family);
    const fallbackAlias = normalized === "birch" ? "brich" : normalized === "brich" ? "birch" : normalized;
    const srcPath = byNormalized.get(normalized) || byNormalized.get(fallbackAlias);
    if (!srcPath) continue;
    try {
      const srcUrl = new URL(srcPath, window.location.origin).toString();
      const res = await fetch(srcUrl, { credentials: "omit", cache: "no-store" });
      if (!res.ok) continue;
      const dataUrl = await blobToDataURL(await res.blob());
      rules.push(
        `@font-face{font-family:"${family}";src:url("${dataUrl}") format("${guessFontFormat(srcPath)}");font-style:normal;font-weight:100 900;font-display:swap;}`
      );
    } catch {
      // best effort
    }
  }

  return rules.join("\n");
}

// ===== CLIENT REMOVE-BG (module scope) =====
function dataURLToBlob(dataURL: string): Blob {
  function blobToDataURL(b: Blob): Promise<string> {
  return new Promise((res) => {
    const fr = new FileReader();
    fr.onload = () => res(String(fr.result));
    fr.readAsDataURL(b);
  });
}

  const [head, b64] = dataURL.split(',');
  const mime = head.match(/data:(.*);base64/)?.[1] || 'image/png';
  const bin = atob(b64);
  const u8 = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
  return new Blob([u8], { type: mime });
}

/** Sends the image to /api/remove-bg and returns a transparent PNG dataURL */
async function removePortraitBackgroundFromURL(url: string): Promise<string> {
  const blob = url.startsWith('data:')
    ? dataURLToBlob(url)
    : await (await fetch(url, { cache: 'no-store' })).blob();

  const fd = new FormData();
  fd.append('image', blob, 'image.png');

  const r = await fetch('/api/remove-bg', { method: 'POST', body: fd });
  if (!r.ok) throw new Error(await r.text());

  const out = await r.blob();
  return await new Promise<string>((res) => {
    const fr = new FileReader();
    fr.onload = () => res(String(fr.result));
    fr.readAsDataURL(out);
  });
}
