const splitRuntimeAssetUrl = (value: string) => {
  const queryIndex = value.indexOf("?");
  const hashIndex = value.indexOf("#");
  const cutIndex =
    queryIndex >= 0 && hashIndex >= 0
      ? Math.min(queryIndex, hashIndex)
      : queryIndex >= 0
      ? queryIndex
      : hashIndex;

  return cutIndex >= 0
    ? { base: value.slice(0, cutIndex), suffix: value.slice(cutIndex) }
    : { base: value, suffix: "" };
};

const resolveRuntimeAssetUrl = (value: string | null | undefined) => {
  const text = typeof value === "string" ? value.trim() : "";
  if (!text || text.startsWith("data:") || text.startsWith("blob:")) return text;

  const { base, suffix } = splitRuntimeAssetUrl(text);
  let lookup = base;
  let absoluteOrigin = "";

  if (/^https?:\/\//i.test(base)) {
    try {
      const url = new URL(base);
      const currentOrigin =
        typeof window !== "undefined" ? window.location.origin : "";
      if (!currentOrigin || url.origin !== currentOrigin) return text;
      lookup = url.pathname;
      absoluteOrigin = url.origin;
    } catch {
      return text;
    }
  }

  const optimized = RUNTIME_OPTIMIZED_ASSET_URLS[lookup];
  if (!optimized) return text;
  return `${absoluteOrigin}${optimized}${suffix}`;
};

const resolveMobileLiveAssetUrl = (
  value: string | null | undefined,
  opts?: { mobile?: boolean; export?: boolean }
) => {
  const runtime = resolveRuntimeAssetUrl(value);
  if (!opts?.mobile || opts?.export) return runtime;
  if (!runtime || runtime.startsWith("data:") || runtime.startsWith("blob:")) return runtime;

  const { base, suffix } = splitRuntimeAssetUrl(runtime);
  let lookup = base;
  let absoluteOrigin = "";

  if (/^https?:\/\//i.test(base)) {
    try {
      const url = new URL(base);
      const currentOrigin =
        typeof window !== "undefined" ? window.location.origin : "";
      if (!currentOrigin || url.origin !== currentOrigin) return runtime;
      lookup = url.pathname;
      absoluteOrigin = url.origin;
    } catch {
      return runtime;
    }
  }

  let mobile = MOBILE_LIVE_ASSET_URLS[lookup];
  if (!mobile) {
    const templateMatch = lookup.match(/^\/templates\/([^/?#]+)\.jpe?g$/i);
    if (templateMatch?.[1]) {
      mobile = `/mobile-assets/templates/${templateMatch[1]}.webp`;
    }
  }
  if (!mobile) return runtime;
  return `${absoluteOrigin}${mobile}${suffix}`;
};

const getMobileLiveAssetDisplaySize = (value: string | null | undefined) => {
  const runtime = resolveRuntimeAssetUrl(value);
  if (!runtime || runtime.startsWith("data:") || runtime.startsWith("blob:")) return null;

  const { base } = splitRuntimeAssetUrl(runtime);
  let lookup = base;
  if (/^https?:\/\//i.test(base)) {
    try {
      const url = new URL(base);
      const currentOrigin =
        typeof window !== "undefined" ? window.location.origin : "";
      if (!currentOrigin || url.origin !== currentOrigin) return null;
      lookup = url.pathname;
    } catch {
      return null;
    }
  }

  return MOBILE_LIVE_ASSET_DISPLAY_SIZES[lookup] ?? null;
};

const normalizeRuntimeAssetRecord = (item: any) => {
  if (!item || typeof item !== "object" || typeof item.url !== "string") return item;
  const url = resolveRuntimeAssetUrl(item.url);
  return url && url !== item.url ? { ...item, url } : item;
};

const CENTER_HERO_BOTTOM_STRIP_IDS = new Set([
  "center_hero_burgundy_bottom_bar",
  "center_teal_bottom_bar",
]);

const isCenterHeroBottomStripAsset = (asset: any) => {
  const id = String(asset?.id || "").toLowerCase();
  return CENTER_HERO_BOTTOM_STRIP_IDS.has(id) || /center.*(bottom|torn).*bar/.test(id);
};

const resolveCanvasAssetName = (asset: any) => {
  if (!asset) return null;

  if ((asset as any).isCircularText) return "Circular Text";

  const explicitLabel = typeof asset.label === "string" ? asset.label.trim() : "";
  if (explicitLabel) return explicitLabel;

  if (isCenterHeroBottomStripAsset(asset)) return "Bottom Strip";

  const baseId = String(asset.id || "").split("_")[1] || "";
  const assetUrl = normalizeAssetLookupValue(resolveRuntimeAssetUrl(String(asset.url || "")));

  const matchByUrl = <T,>(items: readonly T[], getSrc: (item: T) => string) =>
    items.find((item) => normalizeAssetLookupValue(resolveRuntimeAssetUrl(getSrc(item))) === assetUrl) || null;

  const textureById = STUDIO_TEXTURE_LIBRARY.find((item) => item.id === baseId);
  const textureByUrl = matchByUrl(STUDIO_TEXTURE_LIBRARY, (item) => item.src);
  if ((asset as any).isTexture || textureById || textureByUrl) {
    return textureById?.name || textureByUrl?.name || "Texture";
  }

  const separatorById = TEXT_SEPARATOR_GRAPHICS.find((item) => item.id === baseId);
  if ((asset as any).isSeparator || separatorById) {
    return separatorById?.label || "Separator";
  }

  const shapeById = SHAPE_GRAPHICS.find((item) => item.id === baseId);
  if ((asset as any).isShapeGraphic || shapeById) {
    return shapeById?.label || "Shape";
  }

  const stickerById =
    SOCIAL_MEDIA_STICKERS.find((item) => item.id === baseId) ||
    DESIGN_ELEMENTS.find((item) => item.id === baseId) ||
    GRAPHIC_STICKERS.find((item) => item.id === baseId) ||
    STUDIO_GRAPHIC_STICKERS.find((item) => item.id === baseId);
  const stickerByUrl =
    matchByUrl(SOCIAL_MEDIA_STICKERS, (item) => item.src) ||
    matchByUrl(DESIGN_ELEMENTS, (item) => item.src) ||
    matchByUrl(GRAPHIC_STICKERS, (item) => item.src) ||
    matchByUrl(STUDIO_GRAPHIC_STICKERS, (item) => item.src);
  if (stickerById || stickerByUrl) {
    return stickerById?.name || stickerByUrl?.name || "Graphic";
  }

  const nightlifeGraphicById =
    NIGHTLIFE_GRAPHICS.find((item) => item.id === baseId) ||
    STUDIO_NIGHTLIFE_GRAPHICS.find((item) => item.id === baseId);
  if (nightlifeGraphicById) {
    return nightlifeGraphicById.label;
  }

  const flareById =
    FLARE_LIBRARY.find((item) => item.id === baseId) ||
    STUDIO_FLARE_LIBRARY.find((item) => item.id === baseId);
  const flareByUrl =
    matchByUrl(FLARE_LIBRARY, (item) => item.src) ||
    matchByUrl(STUDIO_FLARE_LIBRARY, (item) => item.src);
  if (asset.isFlare || flareById || flareByUrl) {
    return flareById?.name || flareByUrl?.name || "Flare";
  }

  if (asset.isSticker) return "Graphic";
  return null;
};

const normalizeCanvasAssetLabelText = (value: unknown, asset?: any) => {
  const raw = typeof value === "string" ? value : "";
  const normalized = raw.replace(/\\n/g, "\n").replace(/\r\n/g, "\n").trim();
  if (!normalized || normalized.includes("\n")) return normalized;

  if (!asset?.isNightlifeGraphic) return normalized;

  const parts = normalized.split(/\s+/).filter(Boolean);
  if (parts.length === 2) return `${parts[0]}\n${parts[1]}`;

  return normalized;
};

