const inferSubjectFromPrompt = (raw: string) => {
  const prompt = raw.toLowerCase();
  for (const matcher of SUBJECT_MATCHERS) {
    if (matcher.keys.some((k) => prompt.includes(k))) return matcher;
  }
  return null;
};


