type TextPixelHitLayerProps = {
  text: string;
  align?: Align;
  fontFamily?: string;
  fontSize: number;
  fontWeight?: number;
  fontStyle?: React.CSSProperties["fontStyle"];
  lineHeight?: number;
  letterSpacing?: string;
  uppercase?: boolean;
  doubleBreaks?: boolean;
  strokeWidth?: number;
  cursor?: React.CSSProperties["cursor"];
};

function TextPixelHitLayer({
  text,
  align = "left",
  fontFamily = "Inter",
  fontSize,
  fontWeight = 700,
  fontStyle = "normal",
  lineHeight = 1,
  letterSpacing = "0em",
  uppercase = false,
  doubleBreaks = false,
  strokeWidth = 2,
  cursor = "grab",
}: TextPixelHitLayerProps) {
  const safeFontSize = Math.max(1, Number(fontSize) || 12);
  const safeLineHeight = Math.max(0.05, Number(lineHeight) || 1);
  const lines = String(text || "").replace(/\r\n?/g, "\n").split("\n");
  const lineAdvance = safeFontSize * safeLineHeight * (doubleBreaks ? 2 : 1);
  const pad = Math.max(6, safeFontSize * 0.22, strokeWidth * 2);
  const height = pad * 2 + safeFontSize * 1.25 + Math.max(0, lines.length - 1) * lineAdvance;
  const x = align === "right" ? "100%" : align === "center" ? "50%" : "0%";
  const textAnchor = align === "right" ? "end" : align === "center" ? "middle" : "start";

  return (
    <svg
      data-nonexport="true"
      aria-hidden="true"
      focusable="false"
      className="absolute left-0 top-0 overflow-visible"
      width="100%"
      height={height}
      style={{
        width: "100%",
        height: `${height}px`,
        pointerEvents: "none",
        zIndex: 1000,
      }}
    >
      <text
        x={x}
        y={pad + safeFontSize * 0.82}
        textAnchor={textAnchor}
        dominantBaseline="alphabetic"
        fontFamily={fontFamily}
        fontSize={safeFontSize}
        fontWeight={fontWeight}
        fontStyle={fontStyle}
        letterSpacing={letterSpacing}
        fill="#000"
        fillOpacity={0.001}
        stroke="#000"
        strokeOpacity={0.001}
        strokeWidth={Math.max(1, strokeWidth)}
        paintOrder="stroke fill"
        style={{
          cursor,
          pointerEvents: "visiblePainted",
          userSelect: "none",
        }}
      >
        {lines.map((line, index) => (
          <tspan key={`text-hit-${index}`} x={x} dy={index === 0 ? 0 : lineAdvance}>
            {(uppercase ? line.toUpperCase() : line) || " "}
          </tspan>
        ))}
      </text>
    </svg>
  );
}

/* ===== BLOCK: HEADLINE TYPE HELPERS (BEGIN) ===== */
// Simple “hang width” in ems for opening punctuation
const HANG_MAP: Record<string, number> = {
  '"': 0.06, "'": 0.05, '“': 0.08, '‘': 0.07, '«': 0.08, '(': 0.03, '[': 0.03
};

// Common kerning fixes (negative = tighten)
const KERN_MAP: Record<string, number> = {
  'AV': -0.04, 'AW': -0.035, 'AT': -0.03, 'To': -0.03, 'Ta': -0.025, 'Te': -0.02,
  'LA': -0.02, 'LY': -0.03, 'LT': -0.02, 'Yo': -0.02, 'Ya': -0.02, 'Ty': -0.03,
  'VA': -0.045, 'WA': -0.03, 'Ve': -0.02, 'We': -0.02, 'FA': -0.02
};

function applyKerning(line: string, enable = true): React.ReactNode {
  if (!enable || !line) return line;
  const chars = Array.from(line);
  return chars.map((char, i) => {
    const pair = char + (chars[i + 1] || '');
    const adj = KERN_MAP[pair];
    const style: React.CSSProperties | undefined =
      typeof adj === 'number' && i < chars.length - 1
        ? { marginRight: `${adj}em` }
        : undefined;

    return (
      <span key={`c-${i}`} style={style}>
        {char}
      </span>
    );
  });
}

/**
 * Renders headline as block lines:
 * - Adds per-line tracking (lead/last deltas)
 * - Adds optical margin (hanging opening punctuation on first char)
 * - Leaves gradient implementation to the outer wrapper (as you already do)

/* >>> BEGIN — renderHeadlineRich (Safer Version) <<< */
function renderHeadlineRich(
  text: string,
  opts: {
    baseTrackEm: number;
    leadDeltaEm: number;
    lastDeltaEm: number;
    opticalMargin: boolean;
    kerningFix: boolean;
    lineStyle?: React.CSSProperties;
    lineHeight?: React.CSSProperties["lineHeight"];
    fitContentLines?: boolean;
  }
) {
  const lines = String(text || "").split("\n");
  const numericLineHeight =
    typeof opts.lineHeight === "number"
      ? opts.lineHeight
      : typeof opts.lineHeight === "string" && opts.lineHeight.trim() !== ""
      ? Number(opts.lineHeight)
      : NaN;
  const useTightLineAdvance =
    Number.isFinite(numericLineHeight) && numericLineHeight >= 0 && numericLineHeight < 1;

  return (
    <span
      style={{
        display: opts.fitContentLines ? "inline-block" : "block",
        width: opts.fitContentLines ? "max-content" : "100%",
        maxWidth: opts.fitContentLines ? "none" : undefined,
      }}
    >
      {lines.map((ln, idx) => {
        const isFirst = idx === 0;
        const isLast = idx === lines.length - 1;
        const baseLineStyle = opts.lineStyle || {};
        const tightMarginTop =
          useTightLineAdvance && idx > 0 ? `${numericLineHeight - 1}em` : undefined;

        const hang =
          opts.opticalMargin && ln.length ? (HANG_MAP[ln[0]] || 0) : 0;

        const track =
          (opts.baseTrackEm || 0) +
          (isFirst ? (opts.leadDeltaEm || 0) : 0) +
          (isLast ? (opts.lastDeltaEm || 0) : 0);

        return (
          <React.Fragment key={`hl-frag-${idx}`}>
            <span
              style={{
                display: "block", // 👈 This effectively acts as a <br>
                width: opts.fitContentLines ? "max-content" : "100%",
                letterSpacing: `${track}em`,
                marginLeft: hang ? `-${hang}em` : undefined,
                paddingLeft: hang ? `${hang}em` : undefined,
                
                ...baseLineStyle,
                ...(opts.fitContentLines
                  ? {
                      width: "max-content",
                      maxWidth: "none",
                    }
                  : {}),

                // Preserve the requested line advance without letting very low
                // CSS line-height collapse the paint box.
                lineHeight: useTightLineAdvance ? 1 : (opts.lineHeight ?? "inherit"),
                marginTop: tightMarginTop ?? baseLineStyle.marginTop,
              }}
            >
              {ln === "" ? "\u00A0" : applyKerning(ln, opts.kerningFix)}
            </span>
            
            {/* ❌ REMOVED <br /> here. display:block already handles the break. */}
          
          </React.Fragment>
        );
      })}
    </span>
  );
}
