	      `repeating-linear-gradient(${glassScratchAngleA}deg, transparent 0 ${glassRandInt(14, 22)}px, rgba(255,255,255,0.075) ${glassRandInt(23, 27)}px, transparent ${glassRandInt(28, 34)}px)`;
