const findTemplateById = (id: string) => TEMPLATE_GALLERY.find((t) => t.id === id);

type StartupCategoryKey = "dj" | "promoter" | "artist";

function mergeStartupVariant(
  base: Partial<TemplateBase> | undefined,
  preview: string,
  overrides: Partial<TemplateBase>
): TemplateBase {
  const merged: TemplateBase = {
    ...(base ?? {}),
    backgroundUrl:
      typeof base?.backgroundUrl === "string" && base.backgroundUrl.trim().length > 0
        ? base.backgroundUrl
        : typeof (base as any)?.bgUrl === "string" && (base as any).bgUrl.trim().length > 0
        ? String((base as any).bgUrl)
        : preview,
    ...overrides,
  };

  const emojiList = overrides.emojiList ?? base?.emojiList;
  if (Array.isArray(emojiList)) {
    merged.emojiList = [...emojiList];
  }

  const emojis = overrides.emojis ?? base?.emojis;
  if (Array.isArray(emojis)) {
    merged.emojis = [...emojis];
  }

  return merged;
}

