    headlineSize: headManualPx,
    headSizeAuto,
    headMaxPx,
    headlineItalic: textFx.italic,
    headlineBold: textFx.bold,
    headlineUppercase: textFx.uppercase,
    headlineHidden,
    // Position & Rotation
    headX,
    headY,
    headRotate,
    headSkew,
    headSliceEnabled,
    headSliceBandCount,
    headSliceBandGap,
    headSliceEchoDistance,
    headSliceTopColor,
    headSliceMidColor,
    headSliceBottomColor,
    headSliceBlur,
    headSliceFade,
    headSliceShadowStrength,
    headRushEnabled,
    headRushDotColor,
    headRushContrastColor,
    headRushDotSize,
    headRushDotSpacing,
