React.useEffect(() => {
  if (didInitCleanRef.current) return;
  didInitCleanRef.current = true;
  const store = useFlyerState.getState();
  store.setSession({ square: {}, story: {} });
  store.setSessionDirty({ square: false, story: false });
}, []);

const didApplyLadiesNightTestRef = React.useRef(false);
React.useEffect(() => {
  if (didApplyLadiesNightTestRef.current) return;
  if (typeof window === "undefined") return;

  const params = new URLSearchParams(window.location.search);
  const directLadiesNightTest =
    params.get("test") === "ladies-night" ||
    params.get("ladiesNightTest") === "1" ||
    params.get("template") === "ladies_night_center_hero" ||
    params.get("template") === "ladies_night_isolation_test";

  if (!directLadiesNightTest) return;

  const tpl = TEMPLATE_GALLERY.find((item) => item.id === "ladies_night_center_hero");
  if (!tpl) return;

  didApplyLadiesNightTestRef.current = true;
  const targetFormat: Format = params.get("format") === "square" ? "square" : "story";

  setLoadingStartup(false);
  setShowStartup(false);
  setFormat(targetFormat);
  applyTemplateFromGallery(tpl, {
    targetFormat,
    allowStarterPreview: true,
  });

  window.setTimeout(() => {
    const subjectId =
      targetFormat === "story"
        ? "ladies_night_subject_story"
        : "ladies_night_subject_square";
    const store = useFlyerState.getState();
    store.setSelectedPortraitId(subjectId);
    store.setMoveTarget("portrait");
    store.setSelectedPanel("portrait");
  }, 120);
}, [applyTemplateFromGallery]);

const didApplyDirectTemplateRef = React.useRef(false);
React.useEffect(() => {
  if (didApplyDirectTemplateRef.current) return;
  if (typeof window === "undefined") return;

  const params = new URLSearchParams(window.location.search);
  const directTemplateId =
    params.get("leftAlign") === "1"
      ? "square_center_hero_nightlife"
      : params.get("template") || "";

  if (
    !directTemplateId ||
    directTemplateId === "ladies_night_isolation_test" ||
    directTemplateId === "ladies_night_center_hero"
  ) return;

  const tpl = TEMPLATE_GALLERY.find((item) => item.id === directTemplateId);
  if (!tpl) return;

  didApplyDirectTemplateRef.current = true;
  const targetFormat: Format = params.get("format") === "story" ? "story" : "square";

  setLoadingStartup(false);
  setShowStartup(false);
  setFormat(targetFormat);
  applyTemplateFromGallery(tpl, {
    targetFormat,
    allowStarterPreview: true,
  });
}, [applyTemplateFromGallery]);


// keep this new state near the other useStates at the top of your component
const handleTemplateSelect = React.useCallback(
  (key: string, payload?: StartupSelectPayload) => {
    if (isStarterPlan && (key === "dj" || key === "promoter" || key === "artist")) {
      alert("DJ / Artist mode unlocks after login and plan selection.");
      return;
    }
    setLoadingStartup(true);
    setStartupBuildError(null);
    setStartupStudioMode(key === "dj" ? "dj" : null);
    setDjStartupFlowStage("design");
    if (!storageReadyRef.current) {
      pendingStartupSelectionRef.current = { key, payload };
      return;
    }

    runAfterNextPaint(() => {
      try {
        const startupFormat: Format = "square";
        const store = useFlyerState.getState();
        store.setSession((prev) => ({ ...prev, square: {}, story: {} }));
        store.setSessionDirty((prev) => ({ ...prev, square: false, story: false }));
        setFormat(startupFormat);

        if (key === "dj" || key === "promoter" || key === "artist") {
          const startupTemplate = buildStartupCategoryTemplate(key);
          setTemplateId(startupTemplate.id);
          setActiveTemplate(startupTemplate);
          applyTemplate(startupTemplate, { targetFormat: startupFormat, initialLoad: true });

          if (key === "dj") {
            const startupBackground =
              payload?.startupBackgroundDataUrl ||
              payload?.startupBackgroundSrc ||
              DJ_STARTUP_BACKGROUNDS[0].src;
            applyStartupBackground(startupBackground);
            setTextSide("left");
            setHeadAlign("left");
            setAlign("left");
            setTextStyle("headline", startupFormat, { align: "left" });
            setHead2Align("left");
            setTextStyle("headline2", startupFormat, { align: "left" });
            setDetailsAlign("left");
            setDetails2Align("left");
            setVenueAlign("left");
            setSubtagAlign("left");
          }

          if (key === "promoter" || key === "artist") {
            setHeadAlign("center");
            setAlign("center");
            setTextStyle("headline", startupFormat, { align: "center" });
            setHead2Align("center");
            setTextStyle("headline2", startupFormat, { align: "center" });
            setDetailsAlign("center");
            setDetails2Align("center");
            setVenueAlign("center");
            setSubtagAlign("center");
          }
        } else {
          // ✅ Map each vibe to a real template index
          const vibeToTemplateId: Record<string, string> = {
            club: isStarterPlan ? "disco_mirrorball" : "miami2",
            tropical: isStarterPlan ? resolveStarterTemplateChoiceId(1) : "latin_street_tropical",
            luxury: isStarterPlan ? "new-york" : "atlanta",
            urban: "square_center_hero_nightlife",
          };

          const selectedTemplate = TEMPLATE_GALLERY.find((t) => t.id === key);
          const tplId = selectedTemplate?.id ?? vibeToTemplateId[key] ?? TEMPLATE_GALLERY[0]?.id;
          const tpl = selectedTemplate ?? TEMPLATE_GALLERY.find((t) => t.id === tplId);
          if (!tpl) throw new Error("Template not found for vibe: " + key);
          applyTemplateFromGallery(tpl, { targetFormat: startupFormat, allowStarterPreview: true });
          void trackClientEvent("template_selected", {
            properties: {
              source: "startup",
              selection_type: selectedTemplate ? "template_card" : "vibe",
              startup_key: key,
              template_id: tpl.id,
              template_label: tpl.label,
              format: startupFormat,
              mobile: isMobileView,
              guest_mode: isGuestTrial,
              is_starter: isStarterPlan,
            },
          });
        }
      } catch {
        alert("Could not load template.");
      }

      // ✅ Close startup modal once template applied
      setTimeout(() => {
        setLoadingStartup(false);
        setShowStartup(false);
        scrollToArtboard();

        if (key === "dj") {
          setMobileControlsOpen(true);
          setMobileControlsTab("assets");
          useFlyerState.getState().setSelectedPanel(isStarterPlan ? "portrait" : "dj_branding");
          return;
        }

        if (useFlyerState.getState().selectedPanel == null) {
          useFlyerState.getState().setSelectedPanel("template");
        }
      }, 240);
    });

  },
  [
    applyStartupBackground,
    applyTemplate,
    applyTemplateFromGallery,
    isGuestTrial,
    isMobileView,
    isStarterPlan,
    scrollToArtboard,
    setTextStyle,
  ]
);
// === /STARTUP SCREEN ===

React.useEffect(() => {
  if (!storageReady) return;
  const pending = pendingStartupSelectionRef.current;
  if (!pending) return;
  pendingStartupSelectionRef.current = null;
  handleTemplateSelect(pending.key, pending.payload);
}, [storageReady, handleTemplateSelect]);


