const canvasPreloadSignature = React.useMemo(
  () => `${format}:${canvasSize.w}x${canvasSize.h}:${templateId || "custom"}:${canvasPreloadAssets.map((job) => job.key).join(",")}`,
  [canvasPreloadAssets, canvasSize.h, canvasSize.w, format, templateId]
);
