const updateProjectSaveReminderRect = React.useCallback(() => {
  if (typeof window === "undefined") return;
  const node = mobileProjectSaveButtonRef.current;
  if (!node) {
    setProjectSaveReminderRect((prev) => (prev === null ? prev : null));
    return;
  }
  const rect = node.getBoundingClientRect();
  const nextRect = {
    top: Math.round(rect.top),
    left: Math.round(rect.left),
    width: Math.round(rect.width),
    height: Math.round(rect.height),
    bottom: Math.round(rect.bottom),
  };
  setProjectSaveReminderRect((prev) => {
    if (
      prev &&
      prev.top === nextRect.top &&
      prev.left === nextRect.left &&
      prev.width === nextRect.width &&
      prev.height === nextRect.height &&
      prev.bottom === nextRect.bottom
    ) {
      return prev;
    }
    return nextRect;
  });
}, []);
const projectSaveReminderStyle = React.useMemo<React.CSSProperties>(() => {
  if (typeof window === "undefined" || !projectSaveReminderRect) {
    return {
      top: "calc(env(safe-area-inset-top, 0px) + 94px)",
      left: "6px",
      right: "6px",
    };
  }

  const width = Math.min(460, Math.max(280, window.innerWidth - 12));
  const maxLeft = Math.max(6, window.innerWidth - width - 6);
  const left = Math.min(
    maxLeft,
    Math.max(6, projectSaveReminderRect.left + projectSaveReminderRect.width / 2 - width / 2)
  );
  return {
    width,
    top: projectSaveReminderRect.bottom + 10,
    left,
  };
}, [projectSaveReminderRect]);
