const floatingAssetRef = React.useRef<HTMLDivElement | null>(null);
const floatingTextRef = React.useRef<HTMLDivElement | null>(null);
const floatingBgRef = React.useRef<HTMLDivElement | null>(null);
const floatingLightingRef = React.useRef<HTMLDivElement | null>(null);
const floatFocusLockRef = React.useRef(false);
const floatGestureStartedInsideRef = React.useRef(false);
const floatRecentInteractionAtRef = React.useRef(0);
const floatKeyboardSettlingUntilRef = React.useRef(0);

function markFloatInteraction() {
  floatRecentInteractionAtRef.current = Date.now();
}

function isSliderControlTarget(target: EventTarget | null) {
  const el = target as Element | null;
  return !!el?.closest?.('input[type="range"]');
}

function isMobileNumericInputTarget(target: EventTarget | null) {
  const el = target as Element | null;
  return !!el?.closest?.('[data-mobile-numeric-input="true"]');
}

function holdFloatForKeyboardSettle() {
  floatKeyboardSettlingUntilRef.current = Date.now() + 1200;
}

function handleFloatInteractionCapture(e: React.SyntheticEvent) {
  markFloatInteraction();
  floatFocusLockRef.current = true;
  floatGestureStartedInsideRef.current = true;
  if (isMobileNumericInputTarget(e.target)) holdFloatForKeyboardSettle();
  if (isSliderControlTarget(e.target)) return;
  e.stopPropagation();
}

function eventWithinAnyFloat(ev?: Event) {
  const anyEv = ev as any;
  const t = anyEv?.target as HTMLElement | null;
  if (t?.closest?.('[data-floating-controls]')) return true;
  if (t?.closest?.('[data-mobile-float-lock="true"]')) return true;
  const path = (anyEv?.composedPath?.() || []) as any[];
  if (path?.length) {
    for (const node of path) {
      if (!node) continue;
      if ((node as any)?.dataset?.floatingControls) return true;
      if ((node as any)?.dataset?.mobileFloatLock === "true") return true;
      if (floatingTextRef.current && node === floatingTextRef.current) return true;
      if (floatingAssetRef.current && node === floatingAssetRef.current) return true;
      if (floatingBgRef.current && node === floatingBgRef.current) return true;
      if (floatingLightingRef.current && node === floatingLightingRef.current) return true;
    }
  }
  return false;
}

function activeElementWithinAnyFloat() {
  const active = document.activeElement as HTMLElement | null;
  if (!active) return false;
  if (active.closest?.('[data-floating-controls]')) return true;
  if (active.closest?.('[data-mobile-float-lock="true"]')) return true;
  return (
    (floatingTextRef.current && floatingTextRef.current.contains(active)) ||
    (floatingAssetRef.current && floatingAssetRef.current.contains(active)) ||
    (floatingBgRef.current && floatingBgRef.current.contains(active)) ||
    (floatingLightingRef.current && floatingLightingRef.current.contains(active))
  );
}

function mobileFloatInputIsSettling() {
  return Date.now() < floatKeyboardSettlingUntilRef.current;
}

function mobileFloatWasRecentlyInteracted(maxAgeMs = 280) {
  return Date.now() - floatRecentInteractionAtRef.current < maxAgeMs;
}

const hideMobileFloats = React.useCallback(
  (options?: { clearSelection?: boolean }) => {
    floatFocusLockRef.current = false;
    floatGestureStartedInsideRef.current = false;
    floatRecentInteractionAtRef.current = 0;
    floatKeyboardSettlingUntilRef.current = 0;
    setFloatingEditorVisible(false);
    setFloatingAssetVisible(false);
    setFloatingBgVisible(false);
    setFloatingLightingVisible(false);
    if (options?.clearSelection) {
      setSelectedEmojiId(null);
      setSelectedPortraitId(null);
    }
  },
  []
);

const showMobileFloat = React.useCallback(
  (kind: "text" | "asset" | "bg" | "lighting") => {
    floatFocusLockRef.current = false;
    markFloatInteraction();
    setFloatingEditorVisible(kind === "text");
    setFloatingAssetVisible(kind === "asset");
    setFloatingBgVisible(kind === "bg");
    setFloatingLightingVisible(kind === "lighting");
  },
  []
);

function hideAllFloatsAndClearSelection() {
  hideMobileFloats({ clearSelection: true });
}

