// Mobile auto-tab routing:
// - text selections -> Text tab
// - design/background/asset selections -> Design tab
React.useEffect(() => {
  if (!isMobileView || uiMode !== "design") return;

  const textPanels = new Set([
    "template",
    "logo",
    "headline",
    "head2",
    "details",
    "details2",
    "venue",
    "subtag",
    "cinema",
    "mastergrade",
  ]);
  const designPanels = new Set([
    "dj_branding",
    "ai_background",
    "background",
    "bgfx",
    "icons",
    "portrait",
    "project",
  ]);
  if (MAGIC_BLEND_ENABLED) {
    designPanels.add("magic_blend");
  }

  let nextTab: "design" | "assets" | null = null;

  if (selectedPanel === "template" || selectedPanel === "template_backgrounds") {
    nextTab = mobileControlsTab;
  } else if (
    activeTextTarget ||
    moveTarget === "logo" ||
    (selectedPanel ? textPanels.has(selectedPanel) : false)
  ) {
    nextTab = "design"; // Text tab
  } else if (
    !!activeBgControls ||
    hasAssetControls ||
    moveTarget === "background" ||
    moveTarget === "icon" ||
    moveTarget === "portrait" ||
    (selectedPanel ? designPanels.has(selectedPanel) : false)
  ) {
    nextTab = "assets"; // Design tab
  }

  if (nextTab) {
    setMobileControlsOpen(true);
    setMobileControlsTab((current) => (current === nextTab ? current : nextTab));
  }
}, [
  isMobileView,
  uiMode,
  activeTextTarget,
  moveTarget,
  selectedPanel,
  activeBgControls,
  hasAssetControls,
  mobileControlsTab,
]);

// Consolidated scroll/touch hide logic for mobile floats
React.useEffect(() => {
  if (!isMobileView) return;
  const anyMobileFloatVisible =
    floatingEditorVisible ||
    floatingAssetVisible ||
    floatingBgVisible ||
    floatingLightingVisible;
  if (!anyMobileFloatVisible) return;
  if (floatingLightingVisible) return;
  let raf = 0;
  const hideFloats = () => {
    if (raf) return;
    raf = requestAnimationFrame(() => {
      raf = 0;
      if (mobileFloatWasRecentlyInteracted()) return;
      hideAllFloatsAndClearSelection();
    });
  };
  const shouldSkipBecauseDragging = () => {
    if (useFlyerState.getState().isLiveDragging) return true;
    // Custom canvas drags (text/emoji/portrait/flare/background) don't all flip
    // store.isLiveDragging, so guard on active drag data attributes too.
    const hasCanvasDrag =
      typeof document !== "undefined" &&
      !!document.querySelector(
        '[data-hdrag="1"], [data-edrag="1"], [data-pdrag="1"], [data-bgdrag="1"]'
      );
    if (hasCanvasDrag) return true;
    return false;
  };
  const releaseFloatFocus = () => {
    const active = document.activeElement as HTMLElement | null;
    if (active?.closest?.('[data-floating-controls]')) {
      active.blur?.();
    }
    floatFocusLockRef.current = false;
  };
  const onAppScroll = (ev?: Event) => {
    if (shouldSkipBecauseDragging()) return;
    if (
      floatFocusLockRef.current ||
      activeElementWithinAnyFloat() ||
      mobileFloatInputIsSettling() ||
      mobileFloatWasRecentlyInteracted()
    ) return;
    if (eventWithinAnyFloat(ev) || floatGestureStartedInsideRef.current) return;
    releaseFloatFocus();
    hideFloats();
  };
  const onGestureStart = (ev?: Event) => {
    if (shouldSkipBecauseDragging()) return;
    if (
      floatFocusLockRef.current ||
      activeElementWithinAnyFloat() ||
      mobileFloatInputIsSettling() ||
      mobileFloatWasRecentlyInteracted()
    ) return;
    const startedInsideFloat = eventWithinAnyFloat(ev);
    floatGestureStartedInsideRef.current = startedInsideFloat;
    if (startedInsideFloat) return;
    releaseFloatFocus();
    hideFloats();
  };
  const onUserMove = (ev?: Event) => {
    if (shouldSkipBecauseDragging()) return;
    if (
      floatFocusLockRef.current ||
      activeElementWithinAnyFloat() ||
      mobileFloatInputIsSettling() ||
      mobileFloatWasRecentlyInteracted()
    ) return;
    if (eventWithinAnyFloat(ev) || floatGestureStartedInsideRef.current) return;
    releaseFloatFocus();
    hideFloats();
  };
  document.addEventListener("scroll", onAppScroll as any, { passive: true, capture: true });
  window.addEventListener("scroll", onAppScroll as any, { passive: true });
  window.addEventListener("touchstart", onGestureStart as any, { passive: true, capture: true });
  window.addEventListener("pointerdown", onGestureStart as any, { passive: true, capture: true });
  window.addEventListener("touchmove", onUserMove as any, { passive: true, capture: true });
  window.addEventListener("wheel", onUserMove as any, { passive: true, capture: true });
  const release = () => {
    floatFocusLockRef.current = false;
    floatGestureStartedInsideRef.current = false;
  };
  window.addEventListener("pointerup", release, { passive: true });
  window.addEventListener("pointercancel", release, { passive: true });
  window.addEventListener("touchend", release, { passive: true });
  window.addEventListener("touchcancel", release, { passive: true });
  return () => {
    document.removeEventListener("scroll", onAppScroll as any, { capture: true } as any);
    window.removeEventListener("scroll", onAppScroll as any);
    window.removeEventListener("touchstart", onGestureStart as any, { capture: true } as any);
    window.removeEventListener("pointerdown", onGestureStart as any, { capture: true } as any);
    window.removeEventListener("touchmove", onUserMove as any, { capture: true } as any);
    window.removeEventListener("wheel", onUserMove as any, { capture: true } as any);
    window.removeEventListener("pointerup", release);
    window.removeEventListener("pointercancel", release);
    window.removeEventListener("touchend", release);
    window.removeEventListener("touchcancel", release);
    if (raf) cancelAnimationFrame(raf);
  };
}, [
  floatingAssetVisible,
  floatingBgVisible,
  floatingEditorVisible,
  floatingLightingVisible,
  isMobileView,
]);

// Desktop-only: background click-to-edit prototype (guarded by flag)
React.useEffect(() => {
  if (!ENABLE_DESKTOP_BG_CLICK_EDIT) return;
  const art = document.getElementById("artboard");
  if (!art) return;
  if (!ENABLE_CANVAS_BG_CLICK) return;

  const onClick = (e: MouseEvent) => {
    // Desktop only
    if (isMobileView) return;
    if (e.button !== 0) return;
    // avoid clashes with drag/pinch
    if (useFlyerState.getState().isLiveDragging) return;
    const rect = art.getBoundingClientRect();
    const nx = (e.clientX - rect.left) / rect.width;
    const ny = (e.clientY - rect.top) / rect.height;
    setBgEditPopover({
      open: true,
      x: e.clientX,
      y: e.clientY,
      nx,
      ny,
      iw: 0,
      ih: 0,
      prompt: "",
      loading: false,
      error: null,
    });
  };

  art.addEventListener("click", onClick, true);
  return () => art.removeEventListener("click", onClick, true);
}, [isMobileView]);

// Close the prototype popover on escape/scroll
React.useEffect(() => {
  if (!bgEditPopover.open) return;
  const onEsc = (e: KeyboardEvent) => {
    if (e.key === "Escape") setBgEditPopover((s) => ({ ...s, open: false }));
  };
  const onScroll = () => setBgEditPopover((s) => ({ ...s, open: false }));
  window.addEventListener("keydown", onEsc);
  window.addEventListener("scroll", onScroll, { passive: true });
  return () => {
    window.removeEventListener("keydown", onEsc);
    window.removeEventListener("scroll", onScroll);
  };
}, [bgEditPopover.open]);

// Desktop-only: run point->mask->inpaint (via API) for background
const runBgEdit = React.useCallback(async () => {
  if (!ENABLE_DESKTOP_BG_CLICK_EDIT) return;
  if (isMobileView) return;
  const imageUrl = bgUploadUrl || bgUrl;
  if (!imageUrl) {
    setBgEditPopover((s) => ({ ...s, error: "No background image to edit." }));
    return;
  }
  if (!bgEditPopover.prompt.trim()) {
    setBgEditPopover((s) => ({ ...s, error: "Enter a prompt first." }));
    return;
  }
  setBgEditPopover((s) => ({ ...s, loading: true, error: null }));
  try {
    const res = await fetch("/api/edit-region", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        imageUrl,
        x: bgEditPopover.nx,
        y: bgEditPopover.ny,
        prompt: bgEditPopover.prompt,
        imageWidth: bgEditPopover.iw,
        imageHeight: bgEditPopover.ih,
      }),
    });
    if (!res.ok) {
      const txt = await res.text();
      throw new Error(txt || "Edit failed");
    }
    const data = await res.json();
    if (!data?.newImageUrl) throw new Error("No image returned");
    // Preload to avoid flicker
    const img = new Image();
    img.src = data.newImageUrl;
    await img.decode().catch(() => {});
    setBgUrl(data.newImageUrl);
    setBgUploadUrl(null);
    useFlyerState.getState().setSession((prev: any) => ({
      ...prev,
      [format]: { ...(prev?.[format] || {}), bgUrl: data.newImageUrl },
    }));
    setBgEditPopover((s) => ({ ...s, loading: false, open: false }));
  } catch (err: any) {
    setBgEditPopover((s) => ({
      ...s,
      loading: false,
      error:
        err?.message ||
        "Edit failed. Check API token, model access, or try a simpler prompt.",
    }));
  }
}, [bgUploadUrl, bgUrl, bgEditPopover.nx, bgEditPopover.ny, bgEditPopover.prompt, format, isMobileView]);

/* ===== AUTOSAVE: SMART SAVE/LOAD (END) ===== */

React.useEffect(() => {
  if (!storageReady) return;
  if (didCheckSavedDesignRef.current) return;
  didCheckSavedDesignRef.current = true;

  try {
    const clearResumeIntent = () => {
      try { sessionStorage.removeItem("nf:resume"); } catch {}
      try { localStorage.removeItem("nf:resume"); } catch {}
      try { sessionStorage.removeItem(RESUME_META_KEY); } catch {}
      try { localStorage.removeItem(RESUME_META_KEY); } catch {}
      try { sessionStorage.removeItem(RESUME_DESIGN_KEY); } catch {}
    };
    const params = new URLSearchParams(window.location.search);
    const hasDirectTemplateLaunch =
      params.has("template") ||
      params.get("starter") === "nightlife" ||
      params.has("leftAlign") ||
      params.get("test") === "ladies-night" ||
      params.get("ladiesNightTest") === "1";

    if (hasDirectTemplateLaunch) {
      clearResumeIntent();
      setHasSavedDesign(false);
      return;
    }

    const saved =
      sessionStorage.getItem(RESUME_DESIGN_KEY) ||
      localStorage.getItem("nf:lastDesign");
    const wantsResumeFlag =
      sessionStorage.getItem("nf:resume") === "1" ||
      localStorage.getItem("nf:resume") === "1";
    const resumeMetaRaw =
      sessionStorage.getItem(RESUME_META_KEY) ||
      localStorage.getItem(RESUME_META_KEY);

    let validResumeIntent = false;
    if (wantsResumeFlag && resumeMetaRaw) {
      try {
        const meta = JSON.parse(resumeMetaRaw) as {
          source?: string;
          pathname?: string;
          createdAt?: number;
        };
        validResumeIntent =
          meta?.source === "app-navigation" &&
          typeof meta?.pathname === "string" &&
          meta.pathname.startsWith("/") &&
          typeof meta?.createdAt === "number" &&
          Date.now() - meta.createdAt < RESUME_MAX_AGE_MS;
      } catch {
        validResumeIntent = false;
      }
    }

    if (!saved) {
      clearResumeIntent();
      setHasSavedDesign(false);
      return;
    }

    if (validResumeIntent) {
      applyHistorySnapshot(saved);
      setShowStartup(false);
      setHasSavedDesign(false);
      clearResumeIntent();
      return;
    }

    clearResumeIntent();
    try { localStorage.removeItem("nf:lastDesign"); } catch {}
    setHasSavedDesign(true);
    setHasSavedDesign(false);
  } catch {
    setHasSavedDesign(false);
  }
}, [storageReady, applyHistorySnapshot]);

